118→    fun checkRecipientsOkForSending(): Boolean {
119→        recipientMvpView.recipientToTryPerformCompletion()
120→        recipientMvpView.recipientCcTryPerformCompletion()
121→        recipientMvpView.recipientBccTryPerformCompletion()
122→
123→        if (recipientMvpView.recipientToHasUncompletedText()) {
124→            recipientMvpView.showToUncompletedError()
125→            return true
126→        }
127→
128→        if (recipientMvpView.recipientCcHasUncompletedText()) {
129→            recipientMvpView.showCcUncompletedError()
130→            return true
131→        }
132→
133→        if (recipientMvpView.recipientBccHasUncompletedText()) {
134→            recipientMvpView.showBccUncompletedError()
135→            return true
136→        }
137→
138→        if (toAddresses.isEmpty() && ccAddresses.isEmpty() && bccAddresses.isEmpty()) {
139→            recipientMvpView.showNoRecipientsError()
140→            return true
141→        }
142→
143→        return false
