187→    @Override
188→    public List<Recipient> loadInBackground() {
189→        List<Recipient> recipients = new ArrayList<>();
190→        Map<String, Recipient> recipientMap = new HashMap<>();
191→
192→        if (addresses != null) {
193→            fillContactDataFromAddresses(addresses, recipients, recipientMap);
194→        } else if (contactUri != null) {
195→            fillContactDataFromEmailContentUri(contactUri, recipients, recipientMap);
196→        } else if (query != null) {
197→            fillContactDataFromQuery(query, recipients, recipientMap);
198→
199→            if (cryptoProvider != null) {
200→                fillContactDataFromCryptoProvider(query, recipients, recipientMap);
201→            }
202→        } else if (lookupKeyUri != null) {
203→            fillContactDataFromLookupKey(lookupKeyUri, recipients, recipientMap);
204→        } else {
205→            throw new IllegalStateException("loader must be initialized with query or list of addresses!");
206→        }
207→
208→        return fillCryptoStatusData(recipients, recipientMap);
209→    }
