211→    @NonNull
212→    private List<Recipient> fillCryptoStatusData(List<Recipient> recipients, Map<String, Recipient> recipientMap) {
213→        if (recipients.isEmpty()) {
214→            return recipients;
215→        }
216→
217→        if (cryptoProvider != null) {
218→            fillCryptoStatusData(recipientMap);
219→        }
220→
221→        return recipients;
222→    }
