260→    private void fillContactDataFromAddresses(Address[] addresses, List<Recipient> recipients,
261→            Map<String, Recipient> recipientMap) {
262→        for (Address address : addresses) {
263→            if (isSupportedEmailAddress(address.getAddress())) {
264→                // TODO actually query contacts - not sure if this is possible in a single query tho :(
265→                Recipient recipient = new Recipient(address);
266→                recipients.add(recipient);
267→                recipientMap.put(address.getAddress(), recipient);
268→            }
269→        }
270→    }
