335→    @SuppressWarnings("ConstantConditions")
336→    private void fillContactDataFromQuery(String query, List<Recipient> recipients,
337→            Map<String, Recipient> recipientMap) {
338→
339→        boolean foundValidCursor = false;
340→        foundValidCursor |= fillContactDataFromNickname(query, recipients, recipientMap);
341→        foundValidCursor |= fillContactDataFromNameAndEmail(query, recipients, recipientMap, null);
342→
343→        if (foundValidCursor) {
