440→    private void fillContactDataFromCursor(Cursor cursor, List<Recipient> recipients,
441→            Map<String, Recipient> recipientMap, @Nullable Integer maxRecipients) {
442→
443→        while (cursor.moveToNext() && (maxRecipients == null || recipients.size() < maxRecipients)) {
444→            String name = cursor.getString(INDEX_NAME);
445→            String email = cursor.getString(INDEX_EMAIL);
446→
447→            // already exists? just skip then
448→            if (email == null || !isSupportedEmailAddress(email) || recipientMap.containsKey(email)) {
449→                // TODO We should probably merging contacts with the same email address
450→                continue;
451→            }
452→
453→            long contactId = cursor.getLong(INDEX_CONTACT_ID);
454→            String lookupKey = cursor.getString(INDEX_LOOKUP_KEY);
455→            int timesContacted = cursor.getInt(INDEX_TIMES_CONTACTED);
456→            String sortKey = cursor.getString(INDEX_KEY_PRIMARY);
457→            boolean starred = cursor.getInt(INDEX_STARRED) == 1;
458→            int addressType = cursor.getInt(INDEX_EMAIL_TYPE);
459→            String addressLabel = null;
460→            switch (addressType) {
461→                case ContactsContract.CommonDataKinds.Email.TYPE_HOME: {
462→                    addressLabel = getContext().getString(R.string.address_type_home);
463→                    break;
464→                }
465→                case ContactsContract.CommonDataKinds.Email.TYPE_WORK: {
466→                    addressLabel = getContext().getString(R.string.address_type_work);
467→                    break;
468→                }
469→                case ContactsContract.CommonDataKinds.Email.TYPE_OTHER: {
470→                    addressLabel = getContext().getString(R.string.address_type_other);
471→                    break;
472→                }
473→                case ContactsContract.CommonDataKinds.Email.TYPE_MOBILE: {
474→                    // mobile isn't listed as an option contacts app, but it has a constant so we better support it
475→                    addressLabel = getContext().getString(R.string.address_type_mobile);
476→                    break;
477→                }
478→                case ContactsContract.CommonDataKinds.Email.TYPE_CUSTOM: {
479→                    addressLabel = cursor.getString(INDEX_EMAIL_CUSTOM_LABEL);
480→                    break;
481→                }
482→            }
483→
484→            Recipient recipient = new Recipient(name, email, addressLabel, contactId, lookupKey,
485→                    timesContacted, sortKey, starred);
486→
487→            if (recipient.isValidEmailAddress()) {
488→
489→                recipient.photoThumbnailUri =
490→                        cursor.isNull(INDEX_PHOTO_URI) ? null : Uri.parse(cursor.getString(INDEX_PHOTO_URI));
491→                recipientMap.put(email, recipient);
492→                recipients.add(recipient);
493→            }
494→        }
495→
496→        cursor.close();
497→    }
498→
499→    private void fillCryptoStatusData(Map<String, Recipient> recipientMap) {
500→        List<String> recipientList = new ArrayList<>(recipientMap.keySet());
501→        String[] recipientAddresses = recipientList.toArray(new String[recipientList.size()]);
502→
503→        Cursor cursor;
504→        Uri queryUri = Uri.parse("content://" + cryptoProvider + ".provider.exported/autocrypt_status");
505→        try {
506→            cursor = contentResolver.query(queryUri, PROJECTION_CRYPTO_STATUS, null, recipientAddresses, null);
507→        } catch (SecurityException e) {
508→            // TODO escalate error to crypto status?
509→            return;
510→        }
511→
512→        initializeCryptoStatusForAllRecipients(recipientMap);
513→
514→        if (cursor == null) {
515→            return;
516→        }
517→
518→        while (cursor.moveToNext()) {
519→            String email = cursor.getString(INDEX_EMAIL_ADDRESS);
520→            int uidStatus = cursor.getInt(INDEX_EMAIL_STATUS);
521→            int autocryptStatus = cursor.getInt(INDEX_AUTOCRYPT_STATUS);
522→
523→            int effectiveStatus = uidStatus > autocryptStatus ? uidStatus : autocryptStatus;
524→
525→            for (Address address : Address.parseUnencoded(email)) {
526→                String emailAddress = address.getAddress();
527→                if (recipientMap.containsKey(emailAddress)) {
528→                    Recipient recipient = recipientMap.get(emailAddress);
529→                    switch (effectiveStatus) {
530→                        case CRYPTO_PROVIDER_STATUS_UNTRUSTED: {
531→                            if (recipient.getCryptoStatus() == RecipientCryptoStatus.UNAVAILABLE) {
532→                                recipient.setCryptoStatus(RecipientCryptoStatus.AVAILABLE_UNTRUSTED);
533→                            }
534→                            break;
535→                        }
536→                        case CRYPTO_PROVIDER_STATUS_TRUSTED: {
537→                            if (recipient.getCryptoStatus() != RecipientCryptoStatus.AVAILABLE_TRUSTED) {
538→                                recipient.setCryptoStatus(RecipientCryptoStatus.AVAILABLE_TRUSTED);
539→                            }
540→                            break;
541→                        }
542→                    }
543→                }
544→            }
545→        }
546→        cursor.close();
547→
548→        if (observerKey != null) {
549→            observerKey = new ForceLoadContentObserver();
550→            contentResolver.registerContentObserver(queryUri, false, observerKey);
551→        }
552→    }
553→
554→    private void initializeCryptoStatusForAllRecipients(Map<String, Recipient> recipientMap) {
555→        for (Recipient recipient : recipientMap.values()) {
556→            recipient.setCryptoStatus(RecipientCryptoStatus.UNAVAILABLE);
557→        }
558→    }
559→
560→    @Override
561→    public void deliverResult(List<Recipient> data) {
562→        cachedRecipients = data;
563→
564→        if (isStarted()) {
565→            super.deliverResult(data);
566→        }
567→    }
568→
569→    @Override
570→    protected void onStartLoading() {
571→        if (cachedRecipients != null) {
572→            super.deliverResult(cachedRecipients);
573→            return;
574→        }
575→
576→        if (takeContentChanged() || cachedRecipients == null) {
577→            forceLoad();
578→        }
579→    }
580→
581→    @Override
582→    protected void onAbandon() {
583→        super.onAbandon();
584→
585→        if (observerKey != null) {
586→            contentResolver.unregisterContentObserver(observerKey);
587→        }
588→        if (observerContact != null) {
589→            contentResolver.unregisterContentObserver(observerContact);
590→        }
591→    }
592→
593→    private boolean isSupportedEmailAddress(String address) {
594→        return CharsetUtil.isASCII(address);
595→    }
596→}
