211→    fun initFromDraftMessage(message: Message) {
212→        initRecipientsFromDraftMessage(message)
213→
214→        val draftStateHeader = message.getHeader(AutocryptDraftStateHeader.AUTOCRYPT_DRAFT_STATE_HEADER)
215→        if (draftStateHeader.size == 1) {
216→            initEncryptionStateFromDraftStateHeader(draftStateHeader.first())
217→        } else {
218→            initPgpInlineFromDraftMessage(message)
219→        }
220→    }
