222→    private fun initEncryptionStateFromDraftStateHeader(headerValue: String) {
223→        val autocryptDraftStateHeader = draftStateHeaderParser.parseAutocryptDraftStateHeader(headerValue)
224→        if (autocryptDraftStateHeader != null) {
225→            initEncryptionStateFromDraftStateHeader(autocryptDraftStateHeader)
226→        }
227→    }
