235→    private fun initEncryptionStateFromDraftStateHeader(draftState: AutocryptDraftStateHeader) {
236→        isForceTextMessageFormat = draftState.isPgpInline
237→        isReplyToEncryptedMessage = draftState.isReply
238→
239→        if (!draftState.isByChoice) {
240→            // TODO if it's not by choice, we're going with our defaults. should we do something here if those differ?
241→            return
242→        }
243→
244→        currentCryptoMode = when {
245→            draftState.isSignOnly -> CryptoMode.SIGN_ONLY
246→            draftState.isEncrypt -> CryptoMode.CHOICE_ENABLED
247→            else -> CryptoMode.CHOICE_DISABLED
248→        }
249→    }
