578→    private fun toggleEncryptionState(showGotIt: Boolean) {
579→        val currentCryptoStatus = currentCachedCryptoStatus
580→        if (currentCryptoStatus == null) {
581→            Timber.e("click on crypto status while crypto status not available - should not really happen?!")
582→            return
583→        }
584→
585→        if (currentCryptoStatus.isEncryptionEnabled && !currentCryptoStatus.allRecipientsCanEncrypt()) {
586→            recipientMvpView.showOpenPgpEnabledErrorDialog(false)
587→            return
588→        }
589→
590→        if (currentCryptoMode == CryptoMode.SIGN_ONLY) {
591→            recipientMvpView.showErrorIsSignOnly()
592→            return
593→        }
594→
595→        val isEncryptOnNoChoice = currentCryptoStatus.canEncryptAndIsMutualDefault() ||
596→            currentCryptoStatus.isReplyToEncrypted
597→
598→        if (currentCryptoMode == CryptoMode.NO_CHOICE) {
599→            if (currentCryptoStatus.hasAutocryptPendingIntent()) {
600→                recipientMvpView.launchUserInteractionPendingIntent(
601→                    currentCryptoStatus.autocryptPendingIntent,
602→                    REQUEST_CODE_AUTOCRYPT,
603→                )
604→            } else if (isEncryptOnNoChoice) {
605→                // TODO warning dialog if we override, especially from reply!
606→                onCryptoModeChanged(CryptoMode.CHOICE_DISABLED)
607→            } else {
608→                onCryptoModeChanged(CryptoMode.CHOICE_ENABLED)
609→                if (showGotIt) {
610→                    recipientMvpView.showOpenPgpEncryptExplanationDialog()
611→                }
612→            }
613→        } else if (currentCryptoMode == CryptoMode.CHOICE_DISABLED && !isEncryptOnNoChoice) {
614→            onCryptoModeChanged(CryptoMode.CHOICE_ENABLED)
615→        } else {
616→            onCryptoModeChanged(CryptoMode.NO_CHOICE)
617→        }
618→    }
