283→    private void fillContactDataFromLookupKey(Uri lookupKeyUri, List<Recipient> recipients,
284→            Map<String, Recipient> recipientMap) {
285→        // We shouldn't try to access the contacts if we don't have the necessary permission
286→        if (!hasContactPermission())
287→            return;
288→        // We could use the contact id from the URI directly, but getting it from the lookup key is safer
289→        Uri contactContentUri = Contacts.lookupContact(contentResolver, lookupKeyUri);
290→        if (contactContentUri == null) {
291→            return;
292→        }
293→
294→        String contactIdStr = getContactIdFromContactUri(contactContentUri);
295→
296→        Cursor cursor = contentResolver.query(
297→                ContactsContract.CommonDataKinds.Email.CONTENT_URI,
298→                PROJECTION, ContactsContract.CommonDataKinds.Email.CONTACT_ID + "=?",
299→                new String[] { contactIdStr }, null);
300→
301→        if (cursor == null) {
302→            return;
303→        }
304→
305→        fillContactDataFromCursor(cursor, recipients, recipientMap);
306→    }
