358→    private boolean fillContactDataFromNickname(String nickname, List<Recipient> recipients,
359→            Map<String, Recipient> recipientMap) {
360→
361→        boolean hasContact = false;
362→
363→        Uri queryUri = Email.CONTENT_URI;
364→
365→        Cursor nicknameCursor = getNicknameCursor(nickname);
366→
367→        if (nicknameCursor == null) {
368→            return hasContact;
369→        }
370→
371→        try {
372→            while (nicknameCursor.moveToNext()) {
373→                String id = nicknameCursor.getString(INDEX_CONTACT_ID_FOR_NICKNAME);
374→                String selection = ContactsContract.Data.CONTACT_ID + " = ?";
375→                Cursor cursor = contentResolver
376→                        .query(queryUri, PROJECTION, selection, new String[] { id }, SORT_ORDER);
377→
378→                fillContactDataFromCursor(cursor, recipients, recipientMap, null);
379→
380→                hasContact = true;
381→            }
382→        } finally {
383→            nicknameCursor.close();
384→        }
385→
386→        return hasContact;
387→    }
